System.register([],function(e,n){var c,t,o,a,r;return{setters:[],execute:function(){t=(e,n,c,t,o,a)=>({id:e,type:"dialogue",speaker:n,speakerKey:c,text:t,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:a}),o=(e,n,c)=>({id:e,type:"choice",text:n,choices:c,speaker:""}),a=(e,n,c,t,o)=>({id:e,type:"quiz",text:n,quiz:c,onCorrect:t,onWrong:o,speaker:""}),r=(e,n)=>({id:e,type:"system",text:n,speaker:""}),e("chapter4Script",[(c=(e,n,c)=>({id:e,type:"narration",text:n,speaker:"",background:c}))("ch4-0-0",'第4章：能量代谢异常\n\n第3章"所有含金属辅因子的酶停止工作"之后——细胞面临一个根本问题：如何在没有氧化磷酸化的情况下继续产生ATP？',"office"),t("ch4-0-1","陈阳","chenyang","所有人——血糖全在掉。我测了血浆乳酸浓度——比正常值高了8倍。糖酵解在疯狂运转。自从氧化磷酸化停工——我们的细胞失去了TCA循环——失去了电子传递链——只能靠糖酵解产生ATP。","chenyang"),a("ch4-0-2","陈阳举起血糖仪。",{question:"一分子葡萄糖完全氧化为CO₂和H₂O，净产生多少ATP？糖酵解单独只产生多少？",options:[{label:"A",text:"完全氧化30-32 ATP；糖酵解单独2 ATP",correct:!0},{label:"B",text:"完全氧化2 ATP；糖酵解单独30 ATP",correct:!1},{label:"C",text:"两者都是12 ATP",correct:!1},{label:"D",text:"完全氧化129 ATP；糖酵解单独32 ATP",correct:!1}],explanation:"葡萄糖有氧氧化≈30-32 ATP；糖酵解单独只产2 ATP——差了16倍。身体为了弥补这个落差，把糖酵解速率提到了16倍——这就是为什么血糖在狂掉。129 ATP是软脂酸(16碳脂肪酸)完全氧化的净产能量——不是葡萄糖的。",knowledgeId:"glucose_atp_yield",knowledgeTitle:"葡萄糖有氧氧化——30-32 ATP vs 糖酵解2 ATP"},[t("ch4-0-2c","陈阳","chenyang","对。32 vs 2。差了16倍。所以身体把糖酵解提速16倍——这就是为什么我们在低血糖。","chenyang",{affection:{chenyang:5}})],[t("ch4-0-2w","陈阳","chenyang","32个。有氧氧化比糖酵解多16倍。记住这个数——129是软脂酸的数，不是葡萄糖的。这两个数经常被混淆。","chenyang")]),t("ch4-0-3","陈阳","chenyang","二氯乙酸——激活PDH——强制把丙酮酸转为乙酰CoA。即使线粒体停工——乙酰CoA可以转化为酮体——β-羟丁酸——绕过糖酵解——直接为大脑供能。","chenyang"),a("ch4-0-4","陈阳已经在配试剂了。",{question:"酮体包括哪三种？在什么生理状态下酮体成为主要能源？",options:[{label:"A",text:"乙酰乙酸、β-羟丁酸、丙酮；饥饿或糖尿病时肝脏生成酮体供给肝外组织(包括大脑)",correct:!0},{label:"B",text:"乳酸、丙酮酸、乙酰CoA",correct:!1},{label:"C",text:"葡萄糖、果糖、半乳糖",correct:!1},{label:"D",text:"只包括乙酰乙酸",correct:!1}],explanation:"酮体在肝脏线粒体中由乙酰CoA合成(HMG-CoA合酶为关键酶)：乙酰乙酸(~30%)、β-羟丁酸(~70%)和丙酮(微量)。正常脑组织几乎只用葡萄糖；饥饿2-3天后脑改用酮体供能——节省葡萄糖供给红细胞。酮体过多→酮症酸中毒。",knowledgeId:"ketone_bodies",knowledgeTitle:"酮体——饥饿时的替代能源"},[t("ch4-0-4c","陈阳","chenyang","乙酰乙酸、β-羟丁酸、丙酮。肝脏生成——肝外组织利用。你现在就在用这个机制——你的大脑正在靠酮体保持清醒。","chenyang",{affection:{chenyang:5}})],[t("ch4-0-4w","陈阳","chenyang","三种酮体：乙酰乙酸(~30%)、β-羟丁酸(~70%)、丙酮(微量)。饥饿时肝脏生成——大脑和肌肉利用。","chenyang")]),t("ch4-1-0","林雪","linxue","葡萄糖消耗量——比根据乳酸生成量推算的糖酵解通量——多了约30%。这30%的葡萄糖没有变成乳酸——也没有变成CO₂——它去了磷酸戊糖途径(PPP)。","linxue"),a("ch4-1-1","林雪调出¹³C标记葡萄糖的代谢追踪数据。",{question:"磷酸戊糖途径(PPP)的限速酶是什么？NADPH的主要生理功能有哪些？",options:[{label:"A",text:"6-磷酸葡萄糖脱氢酶(G6PD)；NADPH用于脂肪酸合成、维持谷胱甘肽还原状态(抗氧化)、作为加氧酶辅酶",correct:!0},{label:"B",text:"PFK-1；NADPH用于产生ATP",correct:!1},{label:"C",text:"丙酮酸激酶；NADPH是糖酵解的辅酶",correct:!1},{label:"D",text:"己糖激酶；NADPH用于DNA合成",correct:!1}],explanation:"G6PD是PPP限速酶，催化6-磷酸葡萄糖→6-磷酸葡萄糖酸内酯(同时产生NADPH)。G6PD缺乏是全球最常见的酶缺乏症(约4亿人)，导致NADPH不足→谷胱甘肽(GSH)无法维持还原态→红细胞易受氧化损伤→溶血性贫血(蚕豆病)。NADPH三大功能：脂肪酸/胆固醇合成、维持GSH还原态(抗氧化)、NADPH氧化酶和加氧酶的辅酶。",knowledgeId:"ppp_g6pd",knowledgeTitle:"磷酸戊糖途径(PPP)——G6PD与NADPH"},[t("ch4-1-1c","林雪","linxue","我们的细胞把30%的葡萄糖资源从产能转移到了抗氧化防御——因为QZ-1的静电信号产生了大量ROS。活着——比产生ATP更重要。","linxue",{affection:{linxue:5}})],[t("ch4-1-1w","林雪","linxue","G6PD——磷酸戊糖途径的限速酶。缺乏→蚕豆病。NADPH不是用来产ATP的——是用来抗氧化的。","linxue")]),c("ch4-2-0","早上。茶水间。咖啡机前。","breakroom"),o("ch4-2-1","你站在咖啡机前。一个看似无关紧要的选择。但这个选择——会改变本章后半段的走向。",[{text:"【热咖啡】接一杯热气腾腾的黑咖啡",next:[c("ch4-2-1a","热咖啡使你的体温升高0.3°C。Q10系数约为2——温度每升高10°C反应速率翻倍。0.3°C=约2%的代谢差异。\n这点差异在99%的情况下毫无意义——但PDH对温度极其敏感。你的数据比张总预期的高了5%。","breakroom"),c("ch4-2-1a2",'张总当晚在监控报告中标注："适配体代谢恢复速率略高于模型预测。建议增加监控频率。"\n这意味着——他会在第5章提前出手。你少了24小时准备时间。',"breakroom")],effects:{flag:"heat_coffee_chosen",affection:{zhang:-5}}},{text:"【冰咖啡】接一杯冰美式",next:[c("ch4-2-1b","体温不变。PDH激活速率正常。张总的数据符合模型预测——他认为一切在掌控之中——不会急于行动。\n你获得了额外的24小时准备窗口。","breakroom")],effects:{flag:"ice_coffee_chosen"}}]),c("ch4-3-0","傍晚。天台。夕阳把天空染成橙粉色。","rooftop_day"),t("ch4-3-1","陈阳","chenyang",'你知道乳酸吗？所有人都说"乳酸导致肌肉酸痛"——这是错的。乳酸不是废物。肌肉→乳酸→血液→肝脏→糖异生→葡萄糖→肌肉。这就是Cori循环。',"chenyang"),a("ch4-3-2","陈阳在空气中画出代谢通路。",{question:"Cori循环中，肝脏将2分子乳酸经糖异生合成为1分子葡萄糖需要消耗多少高能磷酸键？",options:[{label:"A",text:"2个",correct:!1},{label:"B",text:"6个",correct:!0},{label:"C",text:"不需要——糖异生产生ATP",correct:!1},{label:"D",text:"12个",correct:!1}],explanation:'糖异生从丙酮酸→葡萄糖耗6个高能磷酸键。Cori循环的目的不是产能——而是将乳酸"回收"为葡萄糖——6ATP的代价换取肌肉能继续做糖酵解(产2ATP)。看似"亏本"——但这是无氧条件下唯一能持续供能的方法。肝脏承担了代谢代价。',knowledgeId:"cori_cycle",knowledgeTitle:"Cori循环——6个ATP回收乳酸为葡萄糖"},[t("ch4-3-2c","陈阳","chenyang",'6个ATP——来回收一个"废物"。肝脏承担代价——肌肉获得能量。所以——不是所有被当成废物的东西都真的是废物。乳酸不是。我也不是。你也不是。',"chenyang",{affection:{chenyang:15}})],[t("ch4-3-2w","陈阳","chenyang","6个。记住——Cori循环不是用来产能的——是用6个ATP的代价回收乳酸。","chenyang")]),c("ch4-4-0","深夜。张总办公室。","zhang_office"),t("ch4-4-1","张总","zhang","你们的代谢急救方案——非常有创意。但这不是论文——是人体实验。你们的方案在延长你同事生命的同时——也在消耗你的端粒。","zhang"),t("ch4-4-2","张总","zhang",'你每在这种"战时经济"状态下待一天——就额外消耗0.3次轮回的端粒。你现在大概还有不到18次轮回。三天后——我会启动一个应激测试——你的端粒将在72小时内从23岁加速衰老到85岁。',"zhang"),t("ch4-4-3","张总","zhang","这不是征求你的同意——是给你三天时间准备。用这三天学一切你能学到的东西——因为在加速衰老的72小时里——你只能靠你已经知道的东西来判断怎么活下去。祝你好运。——林远山的儿子。","zhang"),c("ch4-4-4","他走向门口。在开门前——停了一下。没有回头。但你看到他握着门把的手——那只戴着皮质手套的手——在微微发抖。","zhang_office"),r("ch4-end",'▎第4章完成：能量代谢异常\n\n▎新增知识条目：有氧氧化ATP计算 | 酮体代谢 | PPP与G6PD | Cori循环\n▎蝴蝶效应：咖啡选择影响张总在第5章的出手时机\n▎当前SAN值：根据选择动态调整\n\n▎第5章预告：端粒·衰老\n"72小时。从23岁到85岁。你身体里的每一个细胞——都在倒数。"')])}}});